const data = $input.first().json.result || {};

const prompt = `You are the SVP of Sales at Gaming Goods, a digital goods marketplace for the Russian-speaking market.
Today is Monday — generate the weekly B2B sales digest in Russian for the CEO Кирилл.

Available context (last 30 days):

WEB WHALES (top users by GMV):
${JSON.stringify(data.whales_30d || [], null, 2)}

YANDEX MARKET WHALES:
${JSON.stringify(data.ym_whales_30d || [], null, 2)}

PARTNER API GROWTH (B2B already through partner channel):
${JSON.stringify(data.partner_api_growth || [], null, 2)}

WHALES SILENT 14-60 DAYS (potential B2B-recovery targets):
${JSON.stringify(data.recent_silent_whales || [], null, 2)}

Team: CEO Кирилл (strategic deals), Радченко (sales closing), Дмитриев (corporate intros to МТС, Озон, Wildberries), Sasha (CTO, infra).

Tasks:
1. Identify top-3 B2B opportunities for THIS WEEK (existing whale → contract, new partner intro, recovery of silent whale).
2. For each: who owns it (Кир/Радченко/Дмитриев), what concrete action this week, expected outcome.
3. Note any red flags (whale silent that wasn't yesterday, partner growth slowdown).
4. Suggest one bold experiment for May.

Return JSON:
{
  "summary": "1-2 sentences for Telegram",
  "top_3_actions": [
    {"who": "Кир|Радченко|Дмитриев", "action": "...", "outcome": "...", "deadline": "Friday"}
  ],
  "red_flags": ["..."],
  "experiment": "...",
  "telegram_text": "≤400 char Markdown for CEO Telegram"
}
`;
return [{ json: { prompt, raw_data: data } }];

const resp = $input.first().json;
const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
let parsed;
try {
  // strip markdown code fences if present
  const cleaned = text.replace(/^```json\s*/i,'').replace(/```\s*$/,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { summary: 'Parse error', telegram_text: text.slice(0, 400), top_3_actions: [], red_flags: [], experiment: '' };
}
return [{ json: parsed }];

